{
  "family": "Houben-Hoesch Reaction/Synthesis",
  "candidate": {
    "substrate_smiles": [
      "CC#N",
      "COc1cc(OC)cc(OC)c1"
    ],
    "product_smiles": [
      "CC(=O)c1cc(OC)cc(OC)c1O"
    ],
    "optional_reagent_smiles": [
      "Cl[Zn]Cl",
      "Cl"
    ],
    "rationale": "This is a canonical example of the Houben-Hoesch reaction, featuring the acylation of a highly activated, electron-rich aromatic ring (1,3,5-trimethoxybenzene) with a simple nitrile (acetonitrile). The reaction is catalyzed by a Lewis acid (ZnCl2) and HCl, followed by aqueous workup to hydrolyze the intermediate ketimine, yielding the final aryl ketone product. This example clearly illustrates the key transformation: the formation of a C(aryl)-C(acyl) bond.",
    "collision_avoidance_note": "This example uses a simple, acyclic nitrile (acetonitrile) and a highly activated, non-fused aromatic ring (1,3,5-trimethoxybenzene) to avoid overlap with more general Friedel-Crafts acylation reactions, which typically use acyl halides or anhydrides. The use of a nitrile as the electrophile precursor is the defining characteristic of the Houben-Hoesch reaction. The specific substrate is chosen to be highly reactive under these conditions, making it a clear and unambiguous example of this named reaction."
  }
}
